      +'<div><div class="cs-v" style="color:#e67e22">'+ec+'</div><div class="cs-l">en cours</div></div>'
      +'<div><div class="cs-v" style="color:#27ae60">'+re+'</div><div class="cs-l">réalisés</div></div>'
